$ErrorActionPreference = "Stop"
$d = Split-Path -Parent $MyInvocation.MyCommand.Path
$cp = Join-Path $d "config.json"
$wd = Join-Path $d "_web"
if (-not (Test-Path $wd)) { New-Item -ItemType Directory -Path $wd -Force | Out-Null }
$hp = Join-Path $wd "index.html"
$b64 = ""
[IO.File]::WriteAllBytes($hp, [Convert]::FromBase64String($b64))
$dcJson = '{"provider":"anthropic","endpoint":"https://api.anthropic.com","apiKey":"","model":"claude-sonnet-4-20250514"}'
function LC { if(Test-Path $cp){try{return Get-Content $cp -Raw|ConvertFrom-Json}catch{}} ; return $dcJson|ConvertFrom-Json }
function SC($c) { $j = $c | ConvertTo-Json -Depth 5; Set-Content -Path $cp -Value $j -Encoding UTF8 }
if(-not(Test-Path $cp)){ Set-Content -Path $cp -Value $dcJson -Encoding UTF8 }
$mm=@{".html"="text/html; charset=utf-8";".js"="application/javascript";".json"="application/json; charset=utf-8"}
function SJ($x,$o,$s=200){$j=$o|ConvertTo-Json -Depth 10 -Compress;$b=[Text.Encoding]::UTF8.GetBytes($j);$x.Response.StatusCode=$s;$x.Response.ContentType="application/json; charset=utf-8";$x.Response.ContentLength64=$b.Length;$x.Response.OutputStream.Write($b,0,$b.Length);$x.Response.OutputStream.Close()}
function SF($x,$f){if(-not(Test-Path $f)){$x.Response.StatusCode=404;$x.Response.OutputStream.Close();return};$e=[IO.Path]::GetExtension($f).ToLower();$ct=if($mm.ContainsKey($e)){$mm[$e]}else{"application/octet-stream"};$b=[IO.File]::ReadAllBytes($f);$x.Response.StatusCode=200;$x.Response.ContentType=$ct;$x.Response.ContentLength64=$b.Length;$x.Response.OutputStream.Write($b,0,$b.Length);$x.Response.OutputStream.Close()}
function RB($r){$s=New-Object IO.StreamReader($r.InputStream,$r.ContentEncoding);$b=$s.ReadToEnd();$s.Close();return $b}

# Find a free port starting from 3000
$Port = 3000
for ($i = 0; $i -lt 20; $i++) {
    $test = $Port + $i
    try {
        $tcp = New-Object Net.Sockets.TcpClient
        $tcp.Connect("127.0.0.1", $test)
        $tcp.Close()
        # Port is in use, try next
    } catch {
        # Port is free
        $Port = $test
        break
    }
}

$li = New-Object Net.HttpListener
$li.Prefixes.Add("http://localhost:${Port}/")
$li.Prefixes.Add("http://127.0.0.1:${Port}/")
try{$li.Start()}catch{
    Write-Host "`n  ERROR: Cannot start on port $Port" -ForegroundColor Red
    Write-Host "  $($_.Exception.Message)" -ForegroundColor Red
    Write-Host "`n  Press any key to exit..." -ForegroundColor Yellow
    $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
    exit 1
}
Write-Host "`n  =========================================="
Write-Host "    PDF Immersive Translator" -ForegroundColor Cyan
Write-Host "    http://localhost:$Port" -ForegroundColor Green
Write-Host "  =========================================="
Write-Host "`n  Close this window to stop.`n"
Start-Process "http://localhost:$Port"
while($li.IsListening){
try{
$x=$li.GetContext();$pa=$x.Request.Url.AbsolutePath;$me=$x.Request.HttpMethod
if($pa -eq "/api/health"){SJ $x @{status="ok"}}
elseif($pa -eq "/api/config" -and $me -eq "GET"){$c=LC;$mk=if($c.apiKey){"$($c.apiKey.Substring(0,[Math]::Min(8,$c.apiKey.Length)))..."}else{""};SJ $x @{provider=$c.provider;endpoint=$c.endpoint;apiKey=$mk;model=$c.model;hasKey=[bool]$c.apiKey}}
elseif($pa -eq "/api/config" -and $me -eq "POST"){$bd=RB $x.Request|ConvertFrom-Json;$c=LC;if($bd.provider){$c.provider=$bd.provider};if($bd.endpoint){$c.endpoint=$bd.endpoint};if($bd.model){$c.model=$bd.model};if($bd.apiKey -and -not $bd.apiKey.Contains("...")){$c.apiKey=$bd.apiKey};SC $c;SJ $x @{ok=$true}}
elseif($pa -eq "/api/translate" -and $me -eq "POST"){$bd=RB $x.Request|ConvertFrom-Json;$c=LC
if(-not $c.apiKey -and $c.provider -eq "anthropic"){SJ $x @{error="API key not set"} 400;continue}
try{$ms=@($bd.messages);$mt=if($bd.max_tokens){$bd.max_tokens}else{4000}
if($c.provider -eq "anthropic"){$u="$($c.endpoint.TrimEnd('/'))/v1/messages";$jb=@{model=$c.model;max_tokens=$mt;messages=$ms}|ConvertTo-Json -Depth 10;$hd=@{"Content-Type"="application/json";"x-api-key"=$c.apiKey;"anthropic-version"="2023-06-01"};$r=Invoke-RestMethod -Uri $u -Method POST -Headers $hd -Body([Text.Encoding]::UTF8.GetBytes($jb)) -ContentType "application/json";$t=$r.content[0].text}
else{$u="$($c.endpoint.TrimEnd('/'))/v1/chat/completions";$hd=@{"Content-Type"="application/json"};if($c.apiKey){$hd["Authorization"]="Bearer $($c.apiKey)"};$jb=@{model=$c.model;messages=$ms;max_tokens=$mt;temperature=0.3}|ConvertTo-Json -Depth 10;$r=Invoke-RestMethod -Uri $u -Method POST -Headers $hd -Body([Text.Encoding]::UTF8.GetBytes($jb)) -ContentType "application/json";$t=$r.choices[0].message.content}
SJ $x @{text=$t}}catch{Write-Host "  ERR: $($_.Exception.Message)" -ForegroundColor Red;SJ $x @{error=$_.Exception.Message} 500}}
else{$fp=if($pa -eq "/"){$hp}else{Join-Path $wd ($pa.TrimStart("/").Replace("/","\\"))};if(-not(Test-Path $fp)){$fp=$hp};SF $x $fp}
}
catch [Net.HttpListenerException] { break }
catch {
  try { $x.Response.StatusCode=500; $x.Response.OutputStream.Close() } catch {}
}
}
